const express = require('express');
const axios = require('axios');
const { VM } = require('vm2');
const app = express();

app.use(express.json());

const OPENAI_API_KEY = process.env.OPENAI_API_KEY || '';
const ANTHROPIC_API_KEY = process.env.ANTHROPIC_API_KEY || '';
const MODEL_PROVIDER = process.env.MODEL_PROVIDER || 'openai';

async function generateCode(description) {
  const systemPrompt = `You are an expert JavaScript programmer. Generate clean, secure, and executable JavaScript code based on user requirements.
Only return the JavaScript code without markdown formatting, explanations, or code blocks.
The code should be self-contained and executable in a sandboxed environment.
Avoid using external modules unless absolutely necessary.
Use only built-in JavaScript features.`;

  const userPrompt = `Generate JavaScript code for the following requirement:\n\n${description}`;

  if (MODEL_PROVIDER === 'openai') {
    return await generateWithOpenAI(systemPrompt, userPrompt);
  } else if (MODEL_PROVIDER === 'anthropic') {
    return await generateWithAnthropic(systemPrompt, userPrompt);
  } else {
    throw new Error('Invalid MODEL_PROVIDER');
  }
}

async function generateWithOpenAI(systemPrompt, userPrompt) {
  const response = await axios.post(
    'https://api.openai.com/v1/chat/completions',
    {
      model: 'gpt-4',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      temperature: 0.7,
      max_tokens: 2000
    },
    {
      headers: {
        'Authorization': `Bearer ${OPENAI_API_KEY}`,
        'Content-Type': 'application/json'
      }
    }
  );

  return response.data.choices[0].message.content;
}

async function generateWithAnthropic(systemPrompt, userPrompt) {
  const response = await axios.post(
    'https://api.anthropic.com/v1/messages',
    {
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 2000,
      system: systemPrompt,
      messages: [
        { role: 'user', content: userPrompt }
      ]
    },
    {
      headers: {
        'x-api-key': ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'Content-Type': 'application/json'
      }
    }
  );

  return response.data.content[0].text;
}

